    cpu->flags.C = ((v & 0x01u) != 0u);
    uint8_t r = (uint8_t)(v >> 1);
    mc6809_write_byte(cpu, ea, r);
    cpu->flags.N = false;
    cpu->flags.Z = (r == 0u);
    cpu->flags.V = (cpu->flags.N != cpu->flags.C);
