/* DAA - arithmetic */
static void inst_DAA(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t a = cpu->registers[REG_A];
    uint8_t adj = 0u;
    bool c = cpu->flags.C;
    if (((a & 0x0Fu) > 0x09u) || cpu->flags.H) { adj = (uint8_t)(adj | 0x06u); }
    if ((a > 0x99u) || c) { adj = (uint8_t)(adj | 0x60u); c = true; }
    uint16_t t = (uint16_t)a + (uint16_t)adj;
    uint8_t r = (uint8_t)t;
    cpu->registers[REG_A] = r;
    cpu->flags.C = (c || (t > 0xFFu));
    cpu->flags.N = ((r & 0x80u) != 0u);
    cpu->flags.Z = (r == 0u);
    cpu->flags.V = false;
}

