/* EXG - data_transfer */
static void inst_EXG(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t pb = (uint8_t)inst->n;
    uint8_t src = (uint8_t)((pb >> 4) & 0x0Fu);
    uint8_t dst = (uint8_t)(pb & 0x0Fu);
    bool src16 = (src <= 0x04u);
    bool dst16 = (dst <= 0x04u);
    if (src16 != dst16) { return; }
    uint16_t s16 = 0u; uint8_t s8 = 0u;
    switch (src) {
    case 0x0: s16 = (uint16_t)(((uint16_t)cpu->registers[REG_A] << 8) | (uint16_t)cpu->registers[REG_B]); break;
    case 0x1: s16 = cpu->x; break;
    case 0x2: s16 = cpu->y; break;
    case 0x3: s16 = cpu->u; break;
    case 0x4: s16 = cpu->sp; break;
    case 0x8: s8 = cpu->registers[REG_A]; break;
    case 0x9: s8 = cpu->registers[REG_B]; break;
    case 0xA: s8 = cpu->flags.raw; break;
    case 0xB: s8 = cpu->registers[REG_DP]; break;
    default: return;
    }
    uint16_t d16 = 0u; uint8_t d8 = 0u;
    switch (dst) {
    case 0x0: d16 = (uint16_t)(((uint16_t)cpu->registers[REG_A] << 8) | (uint16_t)cpu->registers[REG_B]); break;
    case 0x1: d16 = cpu->x; break;
    case 0x2: d16 = cpu->y; break;
    case 0x3: d16 = cpu->u; break;
    case 0x4: d16 = cpu->sp; break;
    case 0x8: d8 = cpu->registers[REG_A]; break;
    case 0x9: d8 = cpu->registers[REG_B]; break;
    case 0xA: d8 = cpu->flags.raw; break;
    case 0xB: d8 = cpu->registers[REG_DP]; break;
    default: return;
    }
    if (src16) { uint16_t tmp = s16; s16 = d16; d16 = tmp; } else { uint8_t tmp = s8; s8 = d8; d8 = tmp; }
    switch (src) {
    case 0x0: cpu->registers[REG_A] = (uint8_t)((s16 >> 8) & 0xFFu); cpu->registers[REG_B] = (uint8_t)(s16 & 0xFFu); break;
    case 0x1: cpu->x = s16; break; case 0x2: cpu->y = s16; break; case 0x3: cpu->u = s16; break; case 0x4: cpu->sp = s16; break;
    case 0x8: cpu->registers[REG_A] = s8; break; case 0x9: cpu->registers[REG_B] = s8; break; case 0xA: cpu->flags.raw = s8; break; case 0xB: cpu->registers[REG_DP] = s8; break;
    }
    switch (dst) {
    case 0x0: cpu->registers[REG_A] = (uint8_t)((d16 >> 8) & 0xFFu); cpu->registers[REG_B] = (uint8_t)(d16 & 0xFFu); break;
    case 0x1: cpu->x = d16; break; case 0x2: cpu->y = d16; break; case 0x3: cpu->u = d16; break; case 0x4: cpu->sp = d16; break;
    case 0x8: cpu->registers[REG_A] = d8; break; case 0x9: cpu->registers[REG_B] = d8; break; case 0xA: cpu->flags.raw = d8; break; case 0xB: cpu->registers[REG_DP] = d8; break;
    }
}

/* TFR - data_transfer */
